import {
  Box,
  Divider,
  FormControl,
  IconButton,
  InputAdornment,
  InputLabel,
  MenuItem,
  Select,
  TextField,
  Tooltip,
  Typography,
  withStyles,
} from "@material-ui/core"
import React, { useState } from "react"
import _ from "lodash"
import compositeParameters from "../../datasheet/composite_option.yml"
import InfoIcon from "@material-ui/icons/Info"
import GradientIcon from "@material-ui/icons/Gradient"
import VisibilityIcon from "@material-ui/icons/Visibility"
import VisibilityOffIcon from "@material-ui/icons/VisibilityOff"

const ColorTooltip = withStyles(theme => {
  return {
    tooltip: {
      background: "#333",
      color: "#eee",
      borderRadius: "0.2rem",
      boxShadow: "0 0 1rem #3332",
      padding: theme.spacing(2),
      whiteSpace: "pre-wrap",
      fontSize: "0.9em",
    },
  }
})(Tooltip)

const ColorSetting = ({
  stop1,
  stop2,
  setStop1,
  setStop2,
  setGlobalOpacity,
  globalOpacity,
  globalOpacityArray,
  composite,
  setComposite,
}) => {
  const [pinned, setPinned] = useState(true)
  const handleVisClick = e => {
    setPinned(!pinned)
  }
  const handleComposite = e => {
    setComposite(e.target.value)
  }
  const getCompositeTooltip = type => {
    return `Determine how to draw gradient in canvas.\n\n[ ${type} ]\n${compositeParameters[type]}`
  }
  return (
    <div
      className="color-panel"
      style={{
        opacity: pinned ? 0.7 : 0,
        maxHeight: pinned ? "100vh" : "3.5rem",
        maxWidth: pinned ? "16rem" : "12rem",
      }}
    >
      <h2 className="color-panel-header">
        <GradientIcon /> Gradient
      </h2>
      <IconButton
        className="color-panel-vis-btn"
        size="small"
        onClick={handleVisClick}
        aria-label="toggle panel visible"
      >
        {pinned ? <VisibilityIcon /> : <VisibilityOffIcon />}
      </IconButton>
      <form className="color-panel-form" noValidate autoComplete="off">
        <div style={{ display: "flex", alignItems: "center" }}>
          <FormControl variant="outlined" size="small" fullWidth>
            <InputLabel id="demo-simple-select-outlined-label" shrink>
              Composite
            </InputLabel>
            <Select
              labelId="demo-simple-select-outlined-label"
              id="demo-simple-select-outlined"
              value={composite}
              onChange={handleComposite}
              label="Composite"
            >
              {_.map(compositeParameters, (value, key) => {
                return (
                  <MenuItem value={key} key={key}>
                    {key}
                  </MenuItem>
                )
              })}
            </Select>
          </FormControl>
          <ColorTooltip title={getCompositeTooltip(composite)}>
            <InfoIcon />
          </ColorTooltip>
        </div>
        <div
          style={{ display: "flex", alignItems: "center", marginTop: "1rem" }}
        >
          <TextField
            id="outlined-basic"
            label="Opacity"
            variant="outlined"
            size="small"
            type="number"
            min="1"
            max="100"
            InputLabelProps={{
              shrink: true,
            }}
            InputProps={{
              endAdornment: <InputAdornment position="end">%</InputAdornment>,
            }}
            value={globalOpacity}
            onChange={e => {
              const number = Number(e.target.value)
              if (0 < number && number <= 100) {
                setGlobalOpacity(number)
              }
            }}
          />
          <ColorTooltip
            title={
              "Opacity setting for draw.\n\nCan be adjust directly by keyboard number as Photoshop."
            }
          >
            <InfoIcon />
          </ColorTooltip>
        </div>
        <sub className="input-seq-display">
          {globalOpacityArray.length
            ? "Input: " + globalOpacityArray.join("")
            : ""}
        </sub>
      </form>

      <input
        type="color"
        value={stop1}
        onChange={e => setStop1(e.target.value)}
      />
      {"➜"}
      <input
        type="color"
        value={stop2}
        onChange={e => setStop2(e.target.value)}
      />
      <Box pt={2}>
        <Divider />
      </Box>
      <Typography variant="caption" color="textSecondary">
        Click and drag on canvas.
      </Typography>
      <div className="gradient-desc">
        <sub>
          Change the color in this setting panel. Opacity will control new draw
          call transparency, while the composite works similar to Photoshop
          blending option. Consider this canvas as single layer with only
          gradient support.
        </sub>
      </div>
    </div>
  )
}

export default ColorSetting
